commit c40328245e022dd635756af73dbb229abff45912
Author: David Hildenbrand (Arm) <david@kernel.org>

mm/sparse: move memory hotplug bits to sparse-vmemmap.c

This commit moves memory hotplug related code to sparse-vmemmap.c.
It exposes sparse_index_init(), dropping the !CONFIG_SPARSEMEM definition,
and places its declaration in internal.h.

> diff --git a/mm/sparse-vmemmap.c b/mm/sparse-vmemmap.c
> --- a/mm/sparse-vmemmap.c
> +++ b/mm/sparse-vmemmap.c
[ ... ]
> +static void section_deactivate(unsigned long pfn, unsigned long nr_pages,
> +		struct vmem_altmap *altmap)
> +{
[ ... ]
> +	if (!section_is_early) {
> +		memmap_pages_add(-1L * (DIV_ROUND_UP(nr_pages * sizeof(struct page), PAGE_SIZE)));
> +		depopulate_section_memmap(pfn, nr_pages, altmap);
> +	} else if (memmap) {
[ ... ]
> +static struct page * __meminit section_activate(int nid, unsigned long pfn,
> +		unsigned long nr_pages, struct vmem_altmap *altmap,
> +		struct dev_pagemap *pgmap)
> +{
[ ... ]
> +	memmap = populate_section_memmap(pfn, nr_pages, nid, altmap, pgmap);
> +	if (!memmap) {
> +		section_deactivate(pfn, nr_pages, altmap);

If populate_section_memmap() fails here, we call section_deactivate() which
unconditionally decrements the memmap_pages_add() counter. Since the
addition for this section hasn't occurred yet (it happens just below on
success), could this result in a permanent underflow of the counter?

> +		return ERR_PTR(-ENOMEM);
> +	}
> +	memmap_pages_add(DIV_ROUND_UP(nr_pages * sizeof(struct page), PAGE_SIZE));
> +
> +	return memmap;
> +}

